SELECT COUNT(*) FROM users u LEFT JOIN patron_categories pc ON u.patronCategoryId = pc.id WHERE u.role = 'reader'
AND (u.username LIKE CONCAT('%', #{keyword}, '%') OR u.name LIKE CONCAT('%', #{keyword}, '%') OR u.phone LIKE CONCAT('%', #{keyword}, '%') OR pc.name LIKE CONCAT('%', #{keyword}, '%'))
AND u.patronCategoryId = #{patronCategoryId}
